import{_ as i,o as t,c as a,ak as r,an as n,ao as s,ap as o,aq as l,ar as u,as as p}from"./chunks/framework.CRYrbBns.js";const k=JSON.parse('{"title":"Alimentation et régulation des tensions","description":"","frontmatter":{},"headers":[],"relativePath":"12 - Alimentation et régulation des tensions.md","filePath":"12 - Alimentation et régulation des tensions.md"}'),c={name:"12 - Alimentation et régulation des tensions.md"};function m(d,e,g,_,b,h){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="alimentation-et-regulation-des-tensions" tabindex="-1">Alimentation et régulation des tensions <a class="header-anchor" href="#alimentation-et-regulation-des-tensions" aria-label="Permalink to “Alimentation et régulation des tensions”">​</a></h1><p>La batterie alimente l&#39;ensemble de la plateforme en 12V, cependant le Raspberry pi et le bras robot qui seront sur la plateforme ont besoin d&#39;une alimentation de 5V</p><p>Un régulateur de tension nous permet d&#39;abaisser la tension de la batterie 12v à 5v.</p><blockquote><p>⚠️Notre contrainte ici est que l&#39;alimentation 5v doit pouvoir fournir une intensité suffisante, soit environ 7A en crête.</p></blockquote><p>Raspberry pi (<em><strong>3A</strong></em> )+Bras robot (<em><strong>4A</strong></em>) = <strong>7A</strong> max</p><p>Matériel à disposition :</p><ul><li>Régulateur de tension : I-out : 3A. Parfait pour alimenter le bras robot ✅</li><li>Régulateur de tension LM317 : 1,5A. Parfait pour alimenter le Raspberry pi ✅</li></ul><p><img src="'+n+'" alt="alimentation"></p><h2 id="regulateur-lm317-1-5a" tabindex="-1">Régulateur LM317 1,5A <a class="header-anchor" href="#regulateur-lm317-1-5a" aria-label="Permalink to “Régulateur LM317 1,5A”">​</a></h2><blockquote><p>La difficultés rencontré pour ce régulateur est qu&#39;il s&#39;agit d&#39;un composant ayant besoin d&#39;un PCB (circuit imprimé).</p></blockquote><p><a href="https://www.ti.com/lit/ds/symlink/lm317.pdf" target="_blank" rel="noreferrer">Datasheet du LM317</a></p><h3 id="conception-d-un-circuit-imprime-sur-le-logiciel-kicad" tabindex="-1">Conception d&#39;un circuit imprimé sur le logiciel Kicad <a class="header-anchor" href="#conception-d-un-circuit-imprime-sur-le-logiciel-kicad" aria-label="Permalink to “Conception d&#39;un circuit imprimé sur le logiciel Kicad”">​</a></h3><p><img src="'+s+'" alt=""><img src="'+o+'" alt=""></p><h2 id="fabrication-du-circuit-imprime" tabindex="-1">Fabrication du circuit imprimé <a class="header-anchor" href="#fabrication-du-circuit-imprime" aria-label="Permalink to “Fabrication du circuit imprimé”">​</a></h2><blockquote><p>Pour fabriquer nos PCB (circuits imprimés) nous avons choisi d&#39;utiliser une machine disponible au lycée. Cette machine permet de graver des plaques de cuivres et ainsi de dessiner les pistes du circuit imprimé.</p></blockquote><p><img src="'+l+'" alt=""></p><p>Après avoir exporter les fichiers de perçage (.drl) et les fichiers de fabrication (.grb). Nous pouvons paramétrer la machine.</p><p><strong>Exemples de paramètres à renseigner :</strong></p><ul><li>Largeur des pistes</li><li>Diamètre des trous de perçage</li><li>Emplacement des différentes fraises avec leurs diamètres et leurs types.</li><li>Type de matériau à graver (FR4)</li><li>etc.....</li></ul><hr><h2 id="resultat" tabindex="-1">Résultat <a class="header-anchor" href="#resultat" aria-label="Permalink to “Résultat”">​</a></h2><hr><p><img src="'+u+'" alt=""></p><p><img src="'+p+'" alt=""></p><blockquote><p>Une fois les composants soudés, on obtiens un régulateur de tension parfaitement fonctionnel !👍</p></blockquote>',25)])])}const A=i(c,[["render",m]]);export{k as __pageData,A as default};
